                Credits = 4, DepartmentId = 1, DepartmentCode = "CS", DepartmentName = "Computer Science",
                Level = "Intermediate", IsFeatured = false,
                Instructor = new() { Id = 2, Name = "Dr. Robert Nguyen", Title = "Professor", Bio = "Dr. Nguyen is a leading researcher in algorithm optimization with 25 years of teaching experience. His textbook on data structures is used at over 50 universities worldwide.", Email = "rnguyen@university.edu", OfficeLocation = "Science Hall 310" },
                Schedule = new() { Days = "Tue / Thu", Time = "10:30 AM – 12:00 PM", Location = "Room 205", Semester = "Fall 2026" }
            },
            new()
            {
                Id = 3, Code = "CS 310", Title = "Database Systems",
                Description = "Introduction to database design, relational algebra, SQL, normalization, transaction processing, and modern database technologies including NoSQL and cloud databases.",
                Credits = 3, DepartmentId = 1, DepartmentCode = "CS", DepartmentName = "Computer Science",
                Level = "Intermediate", IsFeatured = true,
                Instructor = new() { Id = 1, Name = "Dr. Alice Chen", Title = "Associate Professor", Bio = "Dr. Chen received her Ph.D. from MIT and specializes in programming language theory and CS education. She has published over 40 papers and received the university's Excellence in Teaching award three times.", Email = "achen@university.edu", OfficeLocation = "Science Hall 302" },
                Schedule = new() { Days = "Mon / Wed", Time = "2:00 PM – 3:30 PM", Location = "Room 112", Semester = "Fall 2026" }
            },
            new()
            {
                Id = 4, Code = "MATH 101", Title = "Calculus I",
                Description = "Limits, continuity, differentiation, and integration of single-variable functions. Applications to physics, engineering, and the natural sciences.",
                Credits = 4, DepartmentId = 2, DepartmentCode = "MATH", DepartmentName = "Mathematics",
                Level = "Introductory", IsFeatured = true,
                Instructor = new() { Id = 3, Name = "Dr. Maria Gonzalez", Title = "Professor", Bio = "Dr. Gonzalez is an award-winning educator who has taught calculus for over 20 years. She is known for making abstract concepts accessible and has developed innovative pedagogical approaches adopted across the department.", Email = "mgonzalez@university.edu", OfficeLocation = "Math Building 201" },
                Schedule = new() { Days = "Mon / Wed / Fri", Time = "11:00 AM – 11:50 AM", Location = "Lecture Hall B", Semester = "Fall 2026" }
            },
            new()
            {
                Id = 5, Code = "MATH 210", Title = "Linear Algebra",
                Description = "Vector spaces, linear transformations, matrices, determinants, eigenvalues, and eigenvectors. Applications to computer graphics, data science, and engineering.",
                Credits = 3, DepartmentId = 2, DepartmentCode = "MATH", DepartmentName = "Mathematics",
                Level = "Intermediate", IsFeatured = false,
                Instructor = new() { Id = 4, Name = "Dr. James Park", Title = "Assistant Professor", Bio = "Dr. Park completed his doctorate at Stanford and focuses on applied linear algebra and machine learning. He brings industry experience from his previous role at a major tech company.", Email = "jpark@university.edu", OfficeLocation = "Math Building 115" },
