                Id = 7, Code = "ENG 250", Title = "American Literature",
                Description = "Survey of major works in American literature from the colonial period to the present. Covers poetry, fiction, drama, and essays with attention to historical and cultural context.",
                Credits = 3, DepartmentId = 3, DepartmentCode = "ENG", DepartmentName = "English",
                Level = "Intermediate", IsFeatured = true,
                Instructor = new() { Id = 5, Name = "Prof. Sarah Williams", Title = "Senior Lecturer", Bio = "Prof. Williams is a published author and composition specialist. She has designed the university's writing-across-the-curriculum program and mentors graduate teaching assistants.", Email = "swilliams@university.edu", OfficeLocation = "Humanities 405" },
                Schedule = new() { Days = "Tue / Thu", Time = "3:00 PM – 4:30 PM", Location = "Humanities 102", Semester = "Fall 2026" }
            },
