                Description = "Mechanics, thermodynamics, and waves. Includes laboratory sessions with hands-on experiments. Calculus-based approach suitable for science and engineering majors.",
                Credits = 4, DepartmentId = 4, DepartmentCode = "PHYS", DepartmentName = "Physics",
                Level = "Introductory", IsFeatured = false,
