                Credits = 3, DepartmentId = 5, DepartmentCode = "HIST", DepartmentName = "History",
                Level = "Introductory", IsFeatured = false,
                Instructor = new() { Id = 7, Name = "Dr. Emily Foster", Title = "Associate Professor", Bio = "Dr. Foster specializes in medieval history and cross-cultural exchange. She has conducted research on three continents and brings a global perspective to her teaching.", Email = "efoster@university.edu", OfficeLocation = "Liberal Arts 312" },
                Schedule = new() { Days = "Tue / Thu", Time = "9:00 AM – 10:30 AM", Location = "Liberal Arts 200", Semester = "Fall 2026" }
            },
            new()
            {
                Id = 10, Code = "HIST 220", Title = "Modern American History",
                Description = "American history from Reconstruction to the present day. Topics include industrialization, civil rights, the world wars, the Cold War, and contemporary political and social movements.",
                Credits = 3, DepartmentId = 5, DepartmentCode = "HIST", DepartmentName = "History",
                Level = "Intermediate", IsFeatured = true,
                Instructor = new() { Id = 7, Name = "Dr. Emily Foster", Title = "Associate Professor", Bio = "Dr. Foster specializes in medieval history and cross-cultural exchange. She has conducted research on three continents and brings a global perspective to her teaching.", Email = "efoster@university.edu", OfficeLocation = "Liberal Arts 312" },
                Schedule = new() { Days = "Mon / Wed", Time = "11:00 AM – 12:30 PM", Location = "Liberal Arts 105", Semester = "Fall 2026" }
            },
        };
    }

    public List<Department> GetDepartments() => _departments;

    public Department? GetDepartment(int id) => _departments.FirstOrDefault(d => d.Id == id);

    public List<Course> GetAllCourses() => _courses;

    public List<Course> GetFeaturedCourses() => _courses.Where(c => c.IsFeatured).ToList();

    public Course? GetCourse(int id) => _courses.FirstOrDefault(c => c.Id == id);

    public List<Course> SearchCourses(string? searchTerm, int? departmentId, string? level)
    {
        var query = _courses.AsEnumerable();

        if (!string.IsNullOrWhiteSpace(searchTerm))
        {
            var term = searchTerm.Trim();
            query = query.Where(c =>
                c.Title.Contains(term, StringComparison.OrdinalIgnoreCase) ||
                c.Code.Contains(term, StringComparison.OrdinalIgnoreCase) ||
                c.Description.Contains(term, StringComparison.OrdinalIgnoreCase) ||
                c.Instructor.Name.Contains(term, StringComparison.OrdinalIgnoreCase));
        }

        if (departmentId.HasValue && departmentId.Value > 0)
        {
            query = query.Where(c => c.DepartmentId == departmentId.Value);
        }

        if (!string.IsNullOrWhiteSpace(level))
        {
            query = query.Where(c => c.Level.Equals(level, StringComparison.OrdinalIgnoreCase));
        }

        return query.ToList();
    }
}

