+                Instructor = new() { Id = 6, Name = "Dr. Michael Torres", Title = "Professor", Bio = "Dr. Torres is an experimental physicist whose research focuses on condensed matter physics. He is passionate about undergraduate education and runs an undergraduate research lab.", Email = "mtorres@university.edu", OfficeLocation = "Physics Building 220" },
+                Schedule = new() { Days = "Mon / Wed / Fri", Time = "1:00 PM – 1:50 PM", Location = "Physics 101", Semester = "Fall 2026" }
+            },
+            new()
+            {
+                Id = 9, Code = "HIST 101", Title = "World History to 1500",
+                Description = "Survey of world civilizations from prehistory to 1500 CE. Examines the development of cultures, political systems, trade networks, and intellectual traditions across Africa, Asia, Europe, and the Americas.",
+                Credits = 3, DepartmentId = 5, DepartmentCode = "HIST", DepartmentName = "History",
+                Level = "Introductory", IsFeatured = false,
+                Instructor = new() { Id = 7, Name = "Dr. Emily Foster", Title = "Associate Professor", Bio = "Dr. Foster specializes in medieval history and cross-cultural exchange. She has conducted research on three continents and brings a global perspective to her teaching.", Email = "efoster@university.edu", OfficeLocation = "Liberal Arts 312" },
+                Schedule = new() { Days = "Tue / Thu", Time = "9:00 AM – 10:30 AM", Location = "Liberal Arts 200", Semester = "Fall 2026" }
+            },
