@using CourseCatalog.Models

<div class="card h-100 shadow-sm">
    <div class="card-body">
        <span class="badge bg-primary mb-2">@Course.DepartmentCode</span>
        <span class="badge bg-secondary mb-2">@Course.Credits Credits</span>
        <h5 class="card-title">@Course.Code – @Course.Title</h5>
        <p class="card-text text-muted">@Truncate(Course.Description, 120)</p>
        <p class="card-text"><small>@Course.Instructor.Name · @Course.Schedule.Days</small></p>
    </div>
    <div class="card-footer bg-transparent">
        <a href="courses/@Course.Id" class="btn btn-outline-primary btn-sm">View Details</a>
    </div>
</div>

@code {
    [Parameter, EditorRequired]
    public Course Course { get; set; } = default!;

    private static string Truncate(string text, int maxLength) =>
        text.Length <= maxLength ? text : text[..maxLength] + "…";
}

@using CourseCatalog.Models

<a href="catalog?departmentId=@Department.Id" class="list-group-item list-group-item-action d-flex justify-content-between align-items-center">
    <div>
        <strong>@Department.Code</strong> – @Department.Name
    </div>
    <span class="badge bg-primary rounded-pill">@CourseCount</span>
</a>

@code {
    [Parameter, EditorRequired]
    public Department Department { get; set; } = default!;

    [Parameter]
    public int CourseCount { get; set; }
}

@using CourseCatalog.Models

<div class="row g-3 mb-4">
    <div class="col-md-5">
        <input type="text" class="form-control" placeholder="Search courses, instructors…"
               value="@SearchTerm" @oninput="OnSearchInput" />
    </div>
    <div class="col-md-3">
        <select class="form-select" value="@DepartmentId" @onchange="OnDepartmentChange">
            <option value="0">All Departments</option>
            @foreach (var dept in Departments)
            {
                <option value="@dept.Id">@dept.Code – @dept.Name</option>
            }
        </select>
    </div>
    <div class="col-md-3">
        <select class="form-select" value="@Level" @onchange="OnLevelChange">
            <option value="">All Levels</option>
            <option value="Introductory">Introductory</option>
            <option value="Intermediate">Intermediate</option>
            <option value="Advanced">Advanced</option>
        </select>
    </div>
    <div class="col-md-1">
        <button class="btn btn-outline-secondary w-100" @onclick="ClearFilters" title="Clear filters">✕</button>
    </div>
</div>

@code {
    [Parameter] public string SearchTerm { get; set; } = "";
    [Parameter] public int DepartmentId { get; set; }
    [Parameter] public string Level { get; set; } = "";
    [Parameter] public List<Department> Departments { get; set; } = new();
    [Parameter] public EventCallback<(string Search, int DeptId, string Level)> OnFiltersChanged { get; set; }

    private async Task OnSearchInput(ChangeEventArgs e)
    {
        SearchTerm = e.Value?.ToString() ?? "";
        await NotifyChanged();
    }

    private async Task OnDepartmentChange(ChangeEventArgs e)
    {
        DepartmentId = int.TryParse(e.Value?.ToString(), out var id) ? id : 0;
        await NotifyChanged();
    }

    private async Task OnLevelChange(ChangeEventArgs e)
    {
        Level = e.Value?.ToString() ?? "";
        await NotifyChanged();
    }

    private async Task ClearFilters()
    {
        SearchTerm = "";
        DepartmentId = 0;
        Level = "";
        await NotifyChanged();
    }

    private Task NotifyChanged() =>
        OnFiltersChanged.InvokeAsync((SearchTerm, DepartmentId, Level));
}

