@page "/"
@using CourseCatalog.Models
@using CourseCatalog.Services
@using CourseCatalog.Components.Shared
@inject CatalogService Catalog

<PageTitle>University Course Catalog</PageTitle>

<div class="container py-4">
    <div class="text-center mb-5">
        <h1 class="display-5 fw-bold">🎓 University Course Catalog</h1>
        <p class="lead text-muted">Browse departments, explore courses, and enroll for the upcoming semester.</p>
        <a href="catalog" class="btn btn-primary btn-lg me-2">Browse All Courses</a>
        <a href="enroll" class="btn btn-outline-success btn-lg">Enroll Now</a>
    </div>

    <section class="mb-5">
        <h2 class="mb-3">⭐ Featured Courses</h2>
        <div class="row row-cols-1 row-cols-md-2 row-cols-lg-3 g-4">
            @foreach (var course in _featured)
            {
                <div class="col">
                    <FeaturedCourseCard Course="course" />
                </div>
            }
        </div>
    </section>

    <section>
        <h2 class="mb-3">🏛️ Departments</h2>
        <div class="list-group">
            @foreach (var dept in _departments)
            {
                <DepartmentLink Department="dept" CourseCount="_courseCounts[dept.Id]" />
            }
        </div>
    </section>
</div>

@code {
    private List<Course> _featured = new();
    private List<Department> _departments = new();
    private Dictionary<int, int> _courseCounts = new();

    protected override void OnInitialized()
    {
        _featured = Catalog.GetFeaturedCourses();
        _departments = Catalog.GetDepartments();
        var allCourses = Catalog.GetAllCourses();
        _courseCounts = _departments.ToDictionary(
            d => d.Id,
            d => allCourses.Count(c => c.DepartmentId == d.Id));
    }
}

