 @page "/enroll"
 @using CourseCatalog.Models
 @using CourseCatalog.Services
 @inject CatalogService Catalog

 <PageTitle>Enrollment Request</PageTitle>

 <div class="container py-4">
     <h1 class="mb-4">📝 Enrollment Request</h1>

     @if (_submitted)
     {
         <div class="alert alert-success">
             <h4 class="alert-heading">Request Submitted!</h4>
             <p>Thank you, <strong>@_model.FullName</strong>. Your enrollment request for
                <strong>@_selectedCourseTitle</strong> has been received.</p>
             <p class="mb-0">You will receive a confirmation at your university email. <a href="/">Return to Home</a>.</p>
         </div>
     }
     else
     {
         <div class="row">
             <div class="col-lg-8">
                 <div class="card">
                     <div class="card-body">
                         <EditForm Model="_model" OnValidSubmit="HandleSubmit" FormName="enrollment" Enhance>
                             <DataAnnotationsValidator />
                             <AntiforgeryToken />

                             <div class="mb-3">
                                 <label for="fullName" class="form-label">Full Name <span class="text-danger">*</span></label>
                                 <InputText id="fullName" class="form-control" @bind-Value="_model.FullName" />
                                 <ValidationMessage For="() => _model.FullName" />
                             </div>

                             <div class="mb-3">
                                 <label for="studentId" class="form-label">Student ID <span class="text-danger">*</span></label>
                                 <InputText id="studentId" class="form-control" @bind-Value="_model.StudentId" placeholder="e.g. STU-12345" />
                                 <ValidationMessage For="() => _model.StudentId" />
                             </div>

                             <div class="mb-3">
                                 <label for="courseId" class="form-label">Course <span class="text-danger">*</span></label>
                                 <InputSelect id="courseId" class="form-select" @bind-Value="_model.CourseId">
                                     <option value="0">— Select a course —</option>
                                     @foreach (var course in _courses)
                                     {
                                         <option value="@course.Id">@course.Code – @course.Title (@course.Credits cr.)</option>
                                     }
                                 </InputSelect>
                                 <ValidationMessage For="() => _model.CourseId" />
                             </div>

                             <div class="mb-3">
                                 <label for="notes" class="form-label">Additional Notes</label>
                                 <InputTextArea id="notes" class="form-control" @bind-Value="_model.Notes" rows="3" />
                             </div>

                             <button type="submit" class="btn btn-success">Submit Enrollment Request</button>
                             <a href="catalog" class="btn btn-outline-secondary ms-2">Cancel</a>
                         </EditForm>
                     </div>
                 </div>
             </div>
             <div class="col-lg-4">
                 <div class="card bg-light">
                     <div class="card-body">
                         <h6>ℹ️ How It Works</h6>
                         <ol class="small mb-0">
                             <li>Fill out the form with your details.</li>
                             <li>Select the course you wish to enroll in.</li>
                             <li>Submit your request — you'll receive a confirmation.</li>
                             <li>The registrar will process your request within 2 business days.</li>
                         </ol>
                     </div>
                 </div>
             </div>
         </div>
     }
 </div>

 @code {
     [SupplyParameterFromForm]
     private EnrollmentRequest? _model { get; set; }

     [SupplyParameterFromQuery(Name = "courseId")]
     public int? PreselectedCourseId { get; set; }

     private List<Course> _courses = new();
     private bool _submitted;
     private string _selectedCourseTitle = "";

     protected override void OnInitialized()
     {
         _model ??= new();
         _courses = Catalog.GetAllCourses();

         if (PreselectedCourseId.HasValue && _model.CourseId == 0)
         {
             _model.CourseId = PreselectedCourseId.Value;
         }
     }

     private void HandleSubmit()
     {
         var selected = _courses.FirstOrDefault(c => c.Id == _model.CourseId);
         _selectedCourseTitle = selected is not null ? $"{selected.Code} – {selected.Title}" : "Unknown";
         _submitted = true;
     }
 }

